<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <title>Expense Tracker</title>
    <style>
        body {
            font-family: sans-serif;
            margin: 20px;
        }
        #expense-form {
            display: flex;
            flex-wrap: wrap;
            gap: 10px;
            margin-bottom: 20px;
        }
        #expense-form input, #expense-form select, #expense-form button {
            padding: 5px;
        }
        #form-error {
            color: red;
            margin-top: 5px;
        }
        .expense {
            display: flex;
            justify-content: space-between;
            border-bottom: 1px solid #ccc;
            padding: 5px 0;
        }
        .exp-del {
            cursor: pointer;
        }
    </style>
</head>
<body>
    <h1>Personal Expense Tracker</h1>

    <form id="expense-form">
        <input type="number" id="amount" step="0.01" required>
        <select id="category"></select>
        <input type="date" id="date" required>
        <input type="text" id="note" placeholder="Note (optional)">
        <button type="submit" id="add-expense">Add</button>
        <div id="form-error"></div>
    </form>

    <div>
        <label>Filter by category:
            <select id="filter-category"></select>
        </label>
        <label>From:
            <input type="date" id="filter-from">
        </label>
        <label>To:
            <input type="date" id="filter-to">
        </label>
    </div>

    <div id="expense-list"></div>

    <div>Total: <span id="total">0.00</span></div>

    <div class="cat-totals"></div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            const categorySelect = document.getElementById('category');
            ['groceries', 'transport', 'bills', 'fun'].forEach(cat => {
                const option = document.createElement('option');
                option.value = cat;
                option.textContent = cat.charAt(0).toUpperCase() + cat.slice(1);
                categorySelect.appendChild(option);
            });

            const filterCategorySelect = document.getElementById('filter-category');
            ['all', ...['groceries', 'transport', 'bills', 'fun']].forEach(cat => {
                const option = document.createElement('option');
                option.value = cat;
                option.textContent = cat === 'all' ? 'All' : (cat.charAt(0).toUpperCase() + cat.slice(1));
                filterCategorySelect.appendChild(option);
            });

            let expenses = [];
            try {
                const storedExpenses = localStorage.getItem('expenses');
                if (storedExpenses) {
                    expenses = JSON.parse(storedExpenses);
                }
            } catch(e) {
                console.error('Error loading expenses from storage', e);
            }

            function saveExpenses() {
                localStorage.setItem('expenses', JSON.stringify(expenses));
            }

            document.getElementById('expense-form').addEventListener('submit', function(e) {
                e.preventDefault();
                const amount = parseFloat(document.getElementById('amount').value);
                const category = document.getElementById('category').value;
                const date = document.getElementById('date').value;
                const note = document.getElementById('note').value;

                let errorText = '';
                if (isNaN(amount) || amount <= 0) {
                    errorText += 'Amount must be a positive number.\n';
                }
                if (!date) {
                    errorText += 'Date is required.';
                }

                if (errorText) {
                    document.getElementById('form-error').textContent = errorText;
                    return;
                } else {
                    const newExpense = { amount, category, date, note };
                    expenses.push(newExpense);
                    saveExpenses();
                    renderAll();
                    document.getElementById('amount').value = '';
                    document.getElementById('form-error').textContent = '';
                }
            });

            function renderAll() {
                const listContainer = document.getElementById('expense-list');
                listContainer.innerHTML = '';

                const filterCat = document.getElementById('filter-category').value;
                const from = document.getElementById('filter-from').value;
                const to = document.getElementById('filter-to').value;

                let totalAmount = 0.00;
                const catTotals = {};

                for (let i = expenses.length -1; i >= 0; i--) {
                    const expense = expenses[i];
                    const matchesCat = filterCat === 'all' || expense.category === filterCat;

                    let matchesDate = true;
                    if (from) {
                        matchesDate = expense.date >= from;
                    }
                    if (to && matchesDate) {
                        matchesDate = expense.date <= to;
                    }

                    if (!matchesCat || !matchesDate) continue;

                    const expDiv = document.createElement('div');
                    expDiv.className = 'expense';

                    const formattedAmount = expense.amount.toFixed(2);
                    expDiv.innerHTML = `
                        <span>${formattedAmount}</span>
                        <span>${expense.category}</span>
                        <span>${expense.date}</span>
                        <span>${expense.note || ''}</span>
                    `;

                    const delBtn = document.createElement('button');
                    delBtn.textContent = 'Del';
                    delBtn.className = 'exp-del';

                    delBtn.addEventListener('click', () => {
                        expenses.splice(i, 1);
                        saveExpenses();
                        renderAll();
                    });

                    expDiv.appendChild(delBtn);
                    listContainer.appendChild(expDiv);

                    totalAmount += expense.amount;
                    if (!catTotals[expense.category]) {
                        catTotals[expense.category] = 0;
                    }
                    catTotals[expense.category] += expense.amount;
                }

                document.getElementById('total').textContent = totalAmount.toFixed(2);

                const catTotalsDiv = document.querySelector('.cat-totals');
                catTotalsDiv.innerHTML = '';
                for (const [category, amount] of Object.entries(catTotals)) {
                    const div = document.createElement('div');
                    div.className = 'cat-total';
                    div.setAttribute('data-cat', category);
                    div.textContent = `${category}: ${amount.toFixed(2)}`;
                    catTotalsDiv.appendChild(div);
                }
            }

            document.getElementById('filter-category').addEventListener('change', renderAll);
            document.getElementById('filter-from').addEventListener('input', renderAll);
            document.getElementById('filter-to').addEventListener('input', renderAll);

            renderAll();
        });
    </script>
</body>
</html>
